SELECT button_id
FROM keypad_interactions
WHERE button_id = '1';

SELECT COUNT(*)
FROM keypad_interactions
WHERE action = 'click';

SELECT button_id
FROM pushbutton_details
WHERE replacement_needed = 0;

SELECT input_id 
FROM capacitive_inputs 
WHERE sensitivity_level = 'high';

SELECT interaction_time
FROM keypad_interactions
WHERE interaction_id = 0 AND button_id = '1' AND device_id = 'DeviceA';

SELECT button_id, COUNT(*) AS interaction_count
FROM keypad_interactions
GROUP BY button_id;
